import{_ as a,o as t,c as i,a2 as l}from"./chunks/framework.tNPPebLH.js";const u=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md","lastUpdated":1783841449000}'),d={name:"getting-started.md"};function r(s,e,o,n,p,h){return t(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>本页从下载安装开始，带你完成一次真实宠物导入、检查和打包。一般不需要准备开发环境。</p><h2 id="_1-下载适合当前设备的-studio" tabindex="-1">1. 下载适合当前设备的 Studio <a class="header-anchor" href="#_1-下载适合当前设备的-studio" aria-label="Permalink to &quot;1. 下载适合当前设备的 Studio&quot;">​</a></h2><p>前往 <a href="https://github.com/MingfengHong/petpack/releases" target="_blank" rel="noreferrer">GitHub Releases</a>：</p><table tabindex="0"><thead><tr><th>设备</th><th>下载文件</th></tr></thead><tbody><tr><td>Windows 10/11 x64</td><td><code>PetPack Studio_*_x64-setup.exe</code></td></tr><tr><td>Apple Silicon Mac</td><td>文件名包含 <code>aarch64</code> 的 DMG</td></tr><tr><td>Intel Mac</td><td>文件名包含 <code>x64</code> 或 <code>x86_64</code> 的 DMG</td></tr><tr><td>通用 Linux 桌面</td><td><code>.AppImage</code></td></tr><tr><td>Debian / Ubuntu</td><td><code>.deb</code></td></tr></tbody></table><p>当前社区构建没有商业代码签名。若系统显示 SmartScreen、Gatekeeper 或执行权限提示，请先阅读<a href="./troubleshooting">常见问题与排错</a>。</p><h2 id="_2-准备宠物包" tabindex="-1">2. 准备宠物包 <a class="header-anchor" href="#_2-准备宠物包" aria-label="Permalink to &quot;2. 准备宠物包&quot;">​</a></h2><p>最简单的结构如下：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-pet/</span></span>
<span class="line"><span>├── pet.json</span></span>
<span class="line"><span>└── spritesheet.webp</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>也可以使用：</p><ul><li>包含上述文件的 ZIP；</li><li><code>pet.json</code> 或 spritesheet 文件本身；</li><li>只包含一个宠物子目录的父文件夹；</li><li>Petdex slug，例如 <code>boba</code>；</li><li>Petdex 页面地址，例如 <code>https://petdex.dev/pets/boba</code>。</li></ul><p>图集尺寸和清单字段见<a href="./PET_FORMATS">宠物包格式</a>。</p><h2 id="_3-导入" tabindex="-1">3. 导入 <a class="header-anchor" href="#_3-导入" aria-label="Permalink to &quot;3. 导入&quot;">​</a></h2><p>启动 Studio 后，在“导入宠物”区域：</p><ol><li>点击“选择文件夹”或“选择 ZIP / 文件”；</li><li>也可以把文件夹或 ZIP 直接拖进窗口；</li><li>使用 Petdex 时，在输入框填写 slug 或页面地址，然后点击“识别并导入”。</li></ol><p>导入完成后，Studio 会显示识别格式和图集尺寸。发现阻断问题时，发布按钮保持禁用。</p><h2 id="_4-检查与预览" tabindex="-1">4. 检查与预览 <a class="header-anchor" href="#_4-检查与预览" aria-label="Permalink to &quot;4. 检查与预览&quot;">​</a></h2><p>在“检查与预览”区域确认：</p><ul><li>图集尺寸和行列数量正确；</li><li>使用帧有内容，未使用帧透明；</li><li>清单中的名称、版本和 spritesheet 路径正确；</li><li>待机、移动、挥手、跳跃、失落、等待、工作和检查动作能够正常播放。</li></ul><p>点击“桌面试玩”可以在真正的透明桌宠窗口中检查拖动、缩放和动画效果。</p><h2 id="_5-选择发布方式" tabindex="-1">5. 选择发布方式 <a class="header-anchor" href="#_5-选择发布方式" aria-label="Permalink to &quot;5. 选择发布方式&quot;">​</a></h2><p>校验通过后，“发布桌宠”区域会变为“可以发布”。</p><h3 id="当前平台成品" tabindex="-1">当前平台成品 <a class="header-anchor" href="#当前平台成品" aria-label="Permalink to &quot;当前平台成品&quot;">​</a></h3><p>适合同平台直接分发。点击“选择目录并生成”后会得到：</p><ul><li>原生桌宠运行程序；</li><li><code>petpack.bundle/</code> 宠物资源；</li><li>使用说明和第三方声明；</li><li>可直接发送的 ZIP。</li></ul><h3 id="跨平台构建包" tabindex="-1">跨平台构建包 <a class="header-anchor" href="#跨平台构建包" aria-label="Permalink to &quot;跨平台构建包&quot;">​</a></h3><p>用于把同一个宠物分发到其他操作系统。构建包包含宠物资源、一键入口和目标设备使用说明；缺少对应 builder 时会在首次运行自动下载。详细流程见<a href="./CROSS_PLATFORM">跨平台构建与分发</a>。</p><h2 id="_6-运行桌宠" tabindex="-1">6. 运行桌宠 <a class="header-anchor" href="#_6-运行桌宠" aria-label="Permalink to &quot;6. 运行桌宠&quot;">​</a></h2><p>解压生成的 ZIP，启动其中的桌宠程序：</p><ul><li>桌宠窗口透明、无边框并保持置顶；</li><li>从底部把手拖动位置；</li><li>光标进入宠物区域后显示缩放、动作、置顶和退出工具栏；</li><li>托盘菜单可以显示/隐藏、切换动作和调整大小；</li><li>桌宠不显示在任务栏，关闭或退出应使用悬浮工具栏或托盘菜单。</li></ul><p>接下来可以阅读<a href="./user-guide">完整使用手册</a>，或直接查看<a href="./troubleshooting">常见问题与排错</a>。</p>`,31)])])}const b=a(d,[["render",r]]);export{u as __pageData,b as default};
